import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

import BaseTamplateRequest from '../../consts/BaseTemplateRequest';
import { addRow } from '../../consts/crud';
import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddCrossroadRoadSing() {
    const [road_sing_id, setRoadSingID] = useState('');
    const [crossroad_id, setCrossroadID] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const submitCrossroadRoadSing = async (e) => {
        setLoading(true);

        e.preventDefault();
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        };
        const crossroad_road_sing = { road_sing_id, crossroad_id };
        await addRow('/crossroads/roads/sings', crossroad_road_sing, headers);
        setRoadSingID('');
        setCrossroadID('');
        navigate('/crossroads/roads/sings');

        setLoading(false);
    };

    return (
        <div>
            <BaseTamplateRequest />
            <form className='container' onSubmit={submitCrossroadRoadSing}>
                <h1>Создание знака на перекрестке</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID дорожного знака на дороге</lable>
                    <input 
                        type='text'
                        name='road_sing_id' 
                        value={road_sing_id.road_sing_id} 
                        onChange={(e) => setRoadSingID(e.target.value)}
                        className='form-input'  
                        placeholder='road_sing_id'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>ID перекрестка</lable>
                    <input 
                        type='text'
                        name='crossroad_id' 
                        value={crossroad_id.crossroad_id} 
                        onChange={(e) => setCrossroadID(e.target.value)}
                        className='form-input'  
                        placeholder='crossroad_id'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/crossroads/roads/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )
};

export default AddCrossroadRoadSing;
